#include <imgui.h>

void DrawUiTargetingExample() {
    static bool was_inside_zone = false;
    static bool selected_card = false;

    ImGui::Begin("UI Targeting");
    ImGui::Text("هذا المثال يخص الاستهداف داخل الواجهة، لا التصادم الفيزيائي.");
    ImGui::Separator();

    ImGui::Button("Compile Shader", ImVec2(180.0f, 44.0f));
    const bool button_hovered = ImGui::IsItemHovered();

    selected_card = ImGui::Selectable("Result Card", selected_card, 0, ImVec2(220.0f, 30.0f));
    const bool card_hovered = ImGui::IsItemHovered();

    ImGui::Spacing();
    ImGui::Text("منطقة استهداف عامة:");
    ImVec2 rect_min = ImGui::GetCursorScreenPos();
    ImVec2 rect_size = ImVec2(300.0f, 120.0f);
    ImVec2 rect_max = ImVec2(rect_min.x + rect_size.x, rect_min.y + rect_size.y);
    ImGui::InvisibleButton("hover_zone", rect_size);
    const bool pointer_inside_zone = ImGui::IsMouseHoveringRect(rect_min, rect_max);

    if (pointer_inside_zone && !was_inside_zone) {
        ImGui::SetTooltip("دخل المؤشر منطقة الاستهداف.");
    }
    if (!pointer_inside_zone && was_inside_zone) {
        ImGui::SetTooltip("غادر المؤشر منطقة الاستهداف.");
    }
    was_inside_zone = pointer_inside_zone;

    ImGui::Separator();
    ImGui::Text("Hover فوق الزر: %s", button_hovered ? "نعم" : "لا");
    ImGui::Text("Hover فوق البطاقة: %s", card_hovered ? "نعم" : "لا");
    ImGui::Text("المؤشر داخل المنطقة: %s", pointer_inside_zone ? "نعم" : "لا");
    ImGui::Text("العنصر المحدد: %s", selected_card ? "Result Card" : "لا يوجد");
    ImGui::End();
}

