#include <imgui.h>

void DrawViewportSelectionExample() {
    static bool selecting = false;
    static ImVec2 selection_start(0.0f, 0.0f);
    static ImVec2 selection_end(0.0f, 0.0f);
    static int selected_object = -1;
    static const char* object_names[] = {
        "Crate", "Light", "Camera", "Player"
    };

    ImGui::Begin("Scene View");
    ImGui::Text("هذا المثال يوضح الاستهداف داخل Viewport، لا تصادماً فيزيائياً.");
    ImGui::Separator();

    ImVec2 viewport_min = ImGui::GetCursorScreenPos();
    ImVec2 viewport_size(420.0f, 260.0f);
    ImVec2 viewport_max(viewport_min.x + viewport_size.x, viewport_min.y + viewport_size.y);
    ImGui::InvisibleButton("scene_viewport", viewport_size, ImGuiButtonFlags_MouseButtonLeft);

    const bool viewport_hovered = ImGui::IsItemHovered();
    ImDrawList* draw_list = ImGui::GetWindowDrawList();
    draw_list->AddRectFilled(viewport_min, viewport_max, IM_COL32(18, 28, 42, 255), 12.0f);
    draw_list->AddRect(viewport_min, viewport_max, IM_COL32(88, 124, 164, 255), 12.0f, 0, 2.0f);
    draw_list->AddRectFilled(ImVec2(viewport_min.x + 78.0f, viewport_min.y + 86.0f), ImVec2(viewport_min.x + 138.0f, viewport_min.y + 146.0f), IM_COL32(84, 161, 255, 255), 10.0f);
    draw_list->AddRectFilled(ImVec2(viewport_min.x + 232.0f, viewport_min.y + 112.0f), ImVec2(viewport_min.x + 292.0f, viewport_min.y + 164.0f), IM_COL32(255, 203, 109, 255), 10.0f);

    if (viewport_hovered && ImGui::IsMouseClicked(ImGuiMouseButton_Left)) {
        selecting = true;
        selection_start = ImGui::GetMousePos();
        selection_end = selection_start;
    }

    if (selecting && ImGui::IsMouseDragging(ImGuiMouseButton_Left)) {
        selection_end = ImGui::GetMousePos();
    }

    if (selecting && ImGui::IsMouseReleased(ImGuiMouseButton_Left)) {
        selecting = false;
        selected_object = 0;
    }

    if (selecting) {
        draw_list->AddRectFilled(selection_start, selection_end, IM_COL32(89, 171, 255, 32));
        draw_list->AddRect(selection_start, selection_end, IM_COL32(118, 191, 255, 255), 0.0f, 0, 2.0f);
    }

    ImGui::Separator();
    ImGui::Text("Viewport hovered: %s", viewport_hovered ? "Yes" : "No");
    ImGui::Text("Selecting: %s", selecting ? "Yes" : "No");
    ImGui::Text("Selected object: %s", selected_object >= 0 ? object_names[selected_object] : "None");
    ImGui::End();
}
